const PartnerLogoMarquee = memo(({ isFullColor = false }) => {
  const gapClass = isFullColor 
    ? "gap-12 md:gap-20 pr-12 md:pr-20" 
    : "gap-6 md:gap-10 pr-6 md:pr-10";

  const logoClass = isFullColor
    ? "flex items-center justify-center px-8 md:px-10 py-4 rounded-xl bg-transparent border border-transparent opacity-100 select-none cursor-pointer h-16 md:h-20 max-w-[200px] shrink-0 transition-all duration-300 hover:scale-[1.08] hover:-translate-y-1 hover:shadow-[0_10px_30px_rgba(37,99,235,0.06),0_0_20px_rgba(249,115,22,0.04)] hover:border-blue-200/40"
    : "flex items-center justify-center px-6 md:px-8 py-3 rounded-xl bg-transparent border border-transparent opacity-55 grayscale hover:opacity-100 hover:grayscale-0 hover:scale-[1.08] hover:border-blue-200/50 hover:shadow-[0_8px_30px_rgba(37,99,235,0.06),0_0_15px_rgba(37,99,235,0.05)] transition-all duration-300 select-none cursor-pointer h-12 md:h-16 max-w-[150px] shrink-0";

  return (
    <div className="py-6 select-none relative overflow-hidden w-full group/marquee">
      {/* Dynamic inline styles for infinite scroll */}
      <style>{`
        @keyframes marqueeScrollLeft {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }
        .animate-marquee-loop {
          display: flex;
          width: max-content;
          animation: marqueeScrollLeft 45s linear infinite;
        }
        .group\\/marquee:hover .animate-marquee-loop {
          animation-play-state: paused;
        }
      `}</style>

      {/* Fade shaders on left and right edges */}
      <div className="absolute left-0 top-0 bottom-0 w-20 md:w-36 bg-gradient-to-r from-[#FAFBFF] via-[#FAFBFF]/70 to-transparent z-10 pointer-events-none" />
      <div className="absolute right-0 top-0 bottom-0 w-20 md:w-36 bg-gradient-to-l from-[#FAFBFF] via-[#FAFBFF]/70 to-transparent z-10 pointer-events-none" />

      {/* Infinite scrolling marquee containers */}
      <div className={`animate-marquee-loop items-center ${gapClass}`}>
        {/* Set 1 */}
        <div className={`flex items-center ${gapClass}`}>
          {marqueeItems.map((partner, idx) => (
            <a
              key={`marq1-${partner.name}-${idx}`}
              href={partner.url && partner.url !== '#' ? partner.url : undefined}
              target={partner.url && partner.url !== '#' ? "_blank" : undefined}
              rel="noreferrer"
              className={logoClass}
            >
              {typeof partner.logo === 'function' ? (
                <div className="scale-[1.15] md:scale-[1.40] origin-center flex items-center justify-center"><partner.logo /></div>
              ) : partner.logo ? (
                <>
                  <img 
                    src={partner.logo} 
                    loading="lazy"
                    decoding="async"
                    onError={(e) => { 
                      e.target.onerror = null; 
                      e.target.style.display = 'none'; 
                      const fallback = e.target.nextElementSibling;
                      if (fallback) fallback.style.display = 'block';
                    }}
                    alt={`${partner.name} Logo`} 
                    className={`h-full w-auto object-contain select-none ${isFullColor ? "max-h-[34px] md:max-h-[46px]" : "max-h-[22px] md:max-h-[30px]"}`} 
                  />
                  <span className="hidden text-xs md:text-sm font-black uppercase tracking-widest text-[#2563EB] text-center">{partner.name}</span>
                </>
              ) : (
                <span className="text-xs md:text-sm font-black uppercase tracking-widest text-[#2563EB]">{partner.name}</span>
              )}
            </a>
          ))}
        </div>

        {/* Set 2 (Identical duplicate for seamless snap-wrap) */}
        <div className={`flex items-center ${gapClass}`}>
          {marqueeItems.map((partner, idx) => (
            <a
              key={`marq2-${partner.name}-${idx}`}
              href={partner.url && partner.url !== '#' ? partner.url : undefined}
              target={partner.url && partner.url !== '#' ? "_blank" : undefined}
              rel="noreferrer"
              className={logoClass}
            >
              {typeof partner.logo === 'function' ? (
                <div className="scale-[1.15] md:scale-[1.40] origin-center flex items-center justify-center"><partner.logo /></div>
              ) : partner.logo ? (
                <>
                  <img 
                    src={partner.logo} 
                    loading="lazy"
                    decoding="async"
                    onError={(e) => { 
                      e.target.onerror = null; 
                      e.target.style.display = 'none'; 
                      const fallback = e.target.nextElementSibling;
                      if (fallback) fallback.style.display = 'block';
                    }}
                    alt={`${partner.name} Logo`} 
                    className={`h-full w-auto object-contain select-none ${isFullColor ? "max-h-[34px] md:max-h-[46px]" : "max-h-[22px] md:max-h-[30px]"}`} 
                  />
                  <span className="hidden text-xs md:text-sm font-black uppercase tracking-widest text-[#2563EB] text-center">{partner.name}</span>
                </>
              ) : (
                <span className="text-xs md:text-sm font-black uppercase tracking-widest text-[#2563EB]">{partner.name}</span>
              )}
            </a>
          ))}
        </div>
      </div>
    </div>
  );
});

export default PartnerLogoMarquee;
